// ── API helpers ───────────────────────────────────────────────
const authFetch = async (path, options = {}) => {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/${path}`, {
    headers: { "apikey": SUPABASE_ANON_KEY, "Content-Type": "application/json", ...(options.token ? { "Authorization": `Bearer ${options.token}` } : {}), ...options.headers },
    ...options,
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error_description || data.msg || data.error || "Грешка");
  return data;
};

const sb = async (path, options = {}, token = SUPABASE_ANON_KEY) => {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
    headers: { "apikey": SUPABASE_ANON_KEY, "Authorization": `Bearer ${token}`, "Content-Type": "application/json", "Prefer": options.prefer || "return=representation", ...options.headers },
    ...options,
  });
  if (!res.ok) { const err = await res.json().catch(() => ({})); throw new Error(err.message || res.statusText); }
  const text = await res.text();
  return text ? JSON.parse(text) : null;
};

