const Avatar = ({ profile, size = 40 }) => {
  if (profile?.avatar_url) {
    return <img src={profile.avatar_url} alt="" style={{ width: size, height: size, borderRadius: "50%", objectFit: "cover", flexShrink: 0 }} />;
  }
  const bg = profile?.is_admin ? "linear-gradient(135deg, #4ECDC4, #2BB5AC)" : "linear-gradient(135deg, #FF8B94, #FFB347)";
  return (
    <div style={{ width: size, height: size, borderRadius: "50%", background: bg, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 900, fontSize: size * 0.4, flexShrink: 0 }}>
      {(profile?.name || "?")[0]}
    </div>
  );
};

